"""
astock.auction
竞价条件判断 v2 - 量化规则版

核心原则：
- 竞价区间由"今日实际竞价涨幅" + "昨日是否涨停" 直接决定
- 警告信息量化：触发条件 → 结论 → 操作
- 输出：区间 + 量能要求 + 止损止盈参考价
"""
import math

def calc_auction_range(lb, jb_prob, vr=None, sector_hot=False, phase="退潮",
                       auction_chng=None, zt_yesterday=False, last_close=None):
    """
    综合多因素计算竞价区间。

    核心变化：区间由 auction_chng 直接决定，而非由 jb_prob 反推。
    昨日涨停 + 今日高开 >5% = 一字板形态 → 独立规则

    返回 (ok_min, ok_max, vol_req, warning, stop_loss, take_profit, reasoning)
    """
    reasoning = []
    warnings = []
    stop_loss, take_profit = None, None

    # === 一字板形态 ===
    if zt_yesterday and auction_chng is not None and auction_chng > 5:
        ok_min, ok_max = 0.0, 2.0
        vol_req = "平量/缩量"
        warnings.append(f"一字板高开{auction_chng:+.1f}%→断板>60%")
        if last_close:
            stop_loss = round(last_close * 0.98, 2)
            take_profit = round(last_close * 1.05, 2)
        reasoning.append("一字板形态：仅接受平开或小幅高开")
        return ok_min, ok_max, vol_req, " | ".join(warnings), stop_loss, take_profit, "; ".join(reasoning)

    # === 正常形态：基础区间由板位决定 ===
    if lb >= 5:
        base_min, base_max = 0.5, 3.0
        reasoning.append("5板+，控盘区")
    elif lb == 4:
        base_min, base_max = 1.0, 4.0
        reasoning.append("4板，高位控盘")
    elif lb == 3:
        base_min, base_max = 1.5, 4.5
        reasoning.append("3板，关键分歧位")
    elif lb == 2:
        base_min, base_max = 2.0, 5.0
        reasoning.append("2板，加速期")
    else:
        base_min, base_max = 2.5, 5.5
        reasoning.append("1板，首板观察")

    # ---- 今日竞价涨幅偏离调整 ----
    if auction_chng is not None:
        mid = (base_min + base_max) / 2
        if auction_chng < base_min - 1.0:
            warnings.append(f"竞价{auction_chng:+.1f}%低于预期{base_min:.0f}%→情绪偏弱")
        elif auction_chng > base_max + 2.0:
            warnings.append(f"竞价{auction_chng:+.1f}%高于预期{base_max:.0f}%→过热慎入")

    # ---- 晋级概率调整 ----
    prob = jb_prob
    if prob >= 35:
        adj = -0.5
        reasoning.append(f"高概率{prob:.0f}%→收窄")
    elif prob >= 25:
        adj = 0.0
        reasoning.append(f"中高概率{prob:.0f}%→标准")
    elif prob >= 18:
        adj = +0.3
        reasoning.append(f"中概率{prob:.0f}%→略宽")
    else:
        adj = +0.5
        reasoning.append(f"低概率{prob:.0f}%→从宽")
    base_min += adj
    base_max += adj

    # ---- 量比调整 ----
    vol_req = "平量/缩量"
    if vr is not None:
        if vr < 0.5:
            base_min = max(0.5, base_min - 1.0)
            base_max = base_max - 0.5
            vol_req = "极度缩量优先"
            reasoning.append(f"VR={vr:.2f}极度缩量→控盘信号")
        elif vr < 0.8:
            base_min = max(1.0, base_min - 0.5)
            base_max = base_max - 0.3
            vol_req = "缩量/平量"
            reasoning.append(f"VR={vr:.2f}缩量→控盘偏好")
        elif vr > 2.0:
            base_min = base_min + 0.5
            base_max = base_max + 0.5
            vol_req = "需明显放量"
            reasoning.append(f"VR={vr:.2f}放量→区间上调")
        elif vr > 1.5:
            base_min = base_min + 0.3
            base_max = base_max + 0.3
            vol_req = "温和放量"
            reasoning.append(f"VR={vr:.2f}温和放量→量能支撑")

    # ---- 板块联动 ----
    if sector_hot:
        base_min = max(1.0, base_min - 0.3)
        base_max = base_max - 0.2
        reasoning.append("🚀板块联动→热度缓冲")

    # ---- 市场阶段 ----
    if phase == "退潮":
        base_max = base_max - 0.5
        reasoning.append("退潮期→防御优先")
    elif phase == "冰点":
        base_max = base_max - 0.3
        reasoning.append("冰点期→极度防御")
    elif phase == "发酵":
        base_min = base_min - 0.3
        base_max = base_max + 0.3
        reasoning.append("发酵期→进攻窗口")

    # ---- 最终（四舍五入，避免Python banker's rounding）----
    ok_min = max(0.0, math.floor(base_min * 2 + 0.5) / 2)
    ok_max = max(ok_min + 1.0, math.floor(base_max * 2 + 0.5) / 2)
    ok_max = min(ok_max, 8.0)

    # ---- 量化警告 ----
    if lb >= 4:
        if ok_max >= 4:
            warnings.append(f"⚠️{lb}板：竞价>{ok_max:.0f}%→获利盘砸盘风险")
        if ok_min <= 1:
            warnings.append(f"竞价<{ok_min:.0f}%→情绪弱接力不足")
    elif lb == 3:
        warnings.append("⚠️3板分歧：竞价>4%易炸板")
    if jb_prob < 15:
        warnings.append(f"晋级{jb_prob:.0f}%偏低：需{ok_min:.0f}~{ok_max:.0f}%强势竞价")
    if phase in ("退潮", "冰点"):
        warnings.append(f"⚠️{phase}期：控仓")

    # ---- 止盈止损参考 ----
    if last_close:
        zt_price = round(last_close * 1.10, 2)
        stop_loss = round(zt_price * (1 - ok_max / 100) * 0.97, 2)
        take_profit = zt_price

    if not warnings:
        if sector_hot:
            warnings.append("✅板块联动+情绪支持")
        elif jb_prob >= 25:
            warnings.append("✅晋级概率良好")
        else:
            warnings.append("观察")

    return ok_min, ok_max, vol_req, " | ".join(warnings), stop_loss, take_profit, "; ".join(reasoning)


def auction_ok(code, name, lb, jb_prob, vr=None, sector_hot=False, phase="退潮",
               auction_chng=None, zt_yesterday=False, last_close=None):
    """
    生成竞价观察条件。
    返回 (ok_min, ok_max, vol_req, warning, stop_loss, take_profit, reasoning)
    """
    return calc_auction_range(lb, jb_prob, vr, sector_hot, phase,
                               auction_chng, zt_yesterday, last_close)


# ============================================================
# S/A/B/C 竞价评级（方案新增）
# ============================================================

def auction_tier(code, name, lb, jb_prob, vr=None, auction_chng=None,
                 zt_yesterday=False, phase="退潮", dz_risks=None,
                 ml_prob=None, limit_up_suc_rate=None):
    """
    竞价标的评级 S/A/B/C，直接绑定仓位。

    评估维度（5个）：
        D1 竞价偏离：实际竞价 vs 板块均值的偏离
        D2 量能（VR）：动态合格线（按板位）
        D3 断板风险：断板风险列表
        D4 ML置信度：XGBoost概率
        D5 历史封板率：limit_up_suc_rate

    返回：
        tier: 'S'/'A'/'B'/'C'
        position: 建议仓位（百分比）
        veto_reasons: 否决原因列表（空=可入场）
        details: {dim: (ok/susp/warn) for each dimension}
    """
    dz_risks = dz_risks or []
    details = {}
    veto_reasons = []
    warnings = []

    # ---- D1: 一字板形态直接降级/否决 ----
    if zt_yesterday and auction_chng is not None and auction_chng > 5:
        if auction_chng > 9:
            details["D1_一字板"] = "warn"
            veto_reasons.append(f"一字板高开{auction_chng:.0f}%→断板率>60%")
        else:
            details["D1_一字板"] = "susp"
            warnings.append("一字板形态：严格控仓")

    # ---- D1: 竞价偏离（无板块均值数据，用绝对阈值）----
    if auction_chng is not None:
        if auction_chng < 0:
            details["D1_竞价"] = "warn"
            veto_reasons.append(f"竞价低开{auction_chng:+.1f}%→断板!")
        elif auction_chng > 8:
            details["D1_竞价"] = "susp"
            warnings.append(f"竞价高开{auction_chng:.0f}%→过热慎入")
        elif auction_chng > 5:
            details["D1_竞价"] = "ok"
        else:
            details["D1_竞价"] = "ok"
    else:
        details["D1_竞价"] = "susp"
        warnings.append("竞价数据缺失")

    # ---- D2: VR量能（动态阈值按板位+盘口）----
    if vr is not None:
        if lb >= 5:
            vr_threshold = 0.80
        elif lb >= 3:
            vr_threshold = 1.00
        elif lb >= 1:
            vr_threshold = 1.20
        else:
            vr_threshold = 1.00

        if vr < vr_threshold:
            details["D2_VR"] = "warn"
            veto_reasons.append(f"VR={vr:.2f}<{vr_threshold}量能不足")
        elif vr < vr_threshold * 1.5:
            details["D2_VR"] = "ok"
        else:
            details["D2_VR"] = "ok"  # 放量也正常
    else:
        details["D2_VR"] = "susp"

    # ---- D3: 断板风险列表 ----
    high_risk_keywords = ["一字板高开", "RSI超买", "下降通道", "MACD空头", "断板>"]
    severe_risk = [r for r in dz_risks if any(k in r for k in ["一字板高开", "下降通道+MACD", "断板>60"])]
    moderate_risk = [r for r in dz_risks if any(k in r for k in high_risk_keywords) and not any(k in r for k in severe_risk)]

    if severe_risk:
        details["D3_断板风险"] = "warn"
        veto_reasons.extend(severe_risk)
    elif moderate_risk:
        details["D3_断板风险"] = "susp"
        warnings.extend(moderate_risk)
    else:
        details["D3_断板风险"] = "ok"

    # ---- D4: ML置信度 ----
    if ml_prob is not None:
        if ml_prob >= 0.80:
            details["D4_ML"] = "ok"
        elif ml_prob >= 0.60:
            details["D4_ML"] = "susp"
        else:
            details["D4_ML"] = "warn"
            veto_reasons.append(f"ML概率{ml_prob:.0%}<60%→置信度不足")
    else:
        details["D4_ML"] = "susp"

    # ---- D5: 历史封板率 ----
    if limit_up_suc_rate is not None:
        if limit_up_suc_rate >= 0.90:
            details["D5_封板率"] = "ok"
        elif limit_up_suc_rate >= 0.70:
            details["D5_封板率"] = "susp"
        else:
            details["D5_封板率"] = "warn"
            warnings.append(f"历史封板率{limit_up_suc_rate:.0%}<70%")
    else:
        details["D5_封板率"] = "susp"

    # ---- 综合评级 ----
    warn_count = sum(1 for v in details.values() if v == "warn")
    susp_count = sum(1 for v in details.values() if v == "susp")

    if veto_reasons or warn_count >= 2:
        tier = "C"
        position = 0  # 放弃
    elif warn_count == 1 or susp_count >= 2:
        tier = "B"
        position = 0.30  # 轻仓
    elif susp_count == 1:
        tier = "A"
        position = 0.50  # 半仓
    else:
        tier = "S"
        position = 1.00  # 正常仓位

    # 市场阶段加成
    if phase in ("退潮", "恐慌") and tier in ("S", "A"):
        position = position * 0.70  # 退潮期降仓位30%
        tier = f"{tier}*"
    elif phase == "主升" and tier in ("S", "A"):
        position = min(position * 1.20, 1.0)  # 主升期可加20%
        tier = f"{tier}+"

    return {
        "tier": tier.rstrip("+-"),
        "tier_ext": tier,  # 带修饰符
        "position": round(position, 2),
        "veto_reasons": veto_reasons,
        "warnings": warnings,
        "details": details,
    }


def fmt_auction_tier(tier_info, code, name):
    """格式化评级输出"""
    t = tier_info["tier_ext"]
    pos = tier_info["position"]
    veto = tier_info["veto_reasons"]
    warns = tier_info["warnings"]

    if t.startswith("C"):
        label = f"🔴C级(放弃)"
    elif t.startswith("B"):
        label = f"🟡B级(轻仓{pos:.0%})"
    elif t.startswith("A"):
        label = f"🟡A级(半仓{pos:.0%})"
    elif t.startswith("S"):
        label = f"🟢S级(正常{pos:.0%})"
    else:
        label = f"⚪{t}级"

    lines = [f"  {label} | {code} {name}"]
    for v in veto[:2]:
        lines.append(f"    🔇{v}")
    for w in warns[:2]:
        lines.append(f"    ⚠️{w}")

    return "\n".join(lines)

"""
astock.quicktiny
QuickTiny API 数据源 - A股超短主要数据接口
LB_API_KEY / LB_API_BASE 从环境变量读取
"""
import os, requests, time, json
from datetime import datetime

# API 配置
API_KEY = os.environ.get("LB_API_KEY", "")
API_BASE = os.environ.get("LB_API_BASE", "https://stock.quicktiny.cn/api/openclaw")

HEADERS = {"Authorization": f"Bearer {API_KEY}"}

# ===================== 限流器 =====================
from collections import deque
_call_times = deque()  # 滑动窗口：记录最近60秒内的请求时间戳
_CALLS_PER_MIN = 30

def _wait_for_slot():
    """滑动窗口限流：确保最近60秒内调用次数 < 30"""
    now = time.time()
    # 清除60秒前的旧记录
    while _call_times and now - _call_times[0] > 60:
        _call_times.popleft()
    if len(_call_times) >= _CALLS_PER_MIN:
        # 最旧的请求将在 (60 - elapsed) 秒后过期
        elapsed = now - _call_times[0]
        sleep_time = 60 - elapsed + 0.05
        time.sleep(sleep_time)
        _wait_for_slot()  # 重新检查（递归直到有槽位）
    _call_times.append(time.time())


def _get(endpoint, params=None, retries=2):
    """通用 GET 请求，带重试"""
    url = f"{API_BASE}/{endpoint}"
    # 小延迟防止瞬时超限（不在wait_for_slot里等，_get内部微调）
    time.sleep(0.05)
    for attempt in range(retries + 1):
        try:
            r = requests.get(url, headers=HEADERS, params=params, timeout=10)
            if r.status_code == 429:
                retry_after = int(r.headers.get("retryAfterMs", 60000)) / 1000
                time.sleep(retry_after)
                continue
            if r.status_code != 200:
                return None
            data = r.json()
            return data if data.get("success") else None
        except Exception as e:
            if attempt == retries:
                return None
            time.sleep(1)
    return None


# ===================== 核心接口 =====================


def get_ladder(date):
    """
    涨停梯队（核心接口）。
    date: YYYYMMDD 或 YYYY-MM-DD
    返回 {total_stocks, boards: [{level, stocks: [{...}]}, ...]}
    """
    date_str = str(date).replace("-", "")
    d = _get("ladder", {"date": date_str})
    if not d or "data" not in d:
        return None

    try:
        data = d["data"]
        # 新格式：data.dates[0].boards（2026-03-23起）
        if isinstance(data.get("dates"), list) and len(data["dates"]) > 0:
            board_data = data["dates"][0]
            return {
                "total_stocks": board_data.get("totalStocks", 0),
                "boards": board_data.get("boards", []),
            }
        # 旧格式：data.stocks
        elif isinstance(data.get("stocks"), list):
            return {
                "total_stocks": len(data["stocks"]),
                "boards": data.get("boards", [{"level": 1, "stocks": data["stocks"]}]),
            }
    except (IndexError, KeyError):
        pass
    return None


def get_zt_stocks(date):
    """
    获取涨停股列表（来自ladder接口）。
    返回 [{code, name, level(板位), industry, reason, limit_up_time,
           turnover_rate, order_amount, limit_up_type, limit_up_suc_rate}, ...]
    """
    ladder = get_ladder(date)
    if not ladder:
        return []

    stocks = []
    for board in ladder["boards"]:
        level = board.get("level", 1)
        for s in board.get("stocks", []):
            stocks.append({
                "code": s.get("code", ""),
                "name": s.get("name", ""),
                "level": level,
                "industry": s.get("industry", ""),
                "reason": s.get("reason_type") or (str(s.get("jiuyangongshe_analysis") or "")[:50]),
                "first_limit_up_time": s.get("first_limit_up_time", ""),
                "last_limit_up_time": s.get("last_limit_up_time", ""),
                "turnover_rate": s.get("turnover_rate", 0),
                "order_amount": s.get("order_amount", 0),
                "limit_up_type": s.get("limit_up_type", ""),  # 一字板/换手板/T字板
                "limit_up_suc_rate": s.get("limit_up_suc_rate"),  # 历史晋级率
                "continue_num": s.get("continue_num", level),
                "high_days": s.get("high_days", ""),
                "change_rate": s.get("change_rate", 0),
                "currency_value": s.get("currency_value", 0),
            })
    return stocks


def get_kline_hist(code, days=30, end_date=None):
    """
    获取历史日K线（来自kline接口）。
    code: 6位股票代码，如 '603687'
    返回 [{date, open, high, low, close, volume, amount, pct_chg}, ...]
    """
    params = {"days": days}
    if end_date:
        params["endDate"] = str(end_date).replace("-", "")
    d = _get(f"kline/{code}", params)
    if not d or "data" not in d:
        return []
    raw = d["data"]
    if isinstance(raw, list):
        bars = raw
    else:
        bars = raw.get("klines", [])
    # 按日期升序
    bars = sorted(bars, key=lambda x: str(x.get("date", "")))
    return bars


def get_kline_ohlcv(code, days=60):
    """
    获取简化OHLCV数据（用于技术指标计算）。
    返回 (dates, opens, highs, lows, closes, vols)
    """
    bars = get_kline_hist(code, days=days)
    if not bars:
        return [], [], [], [], [], []
    try:
        dates = [b["date"] for b in bars]
        opens = [float(b["open"]) for b in bars]
        highs = [float(b["high"]) for b in bars]
        lows = [float(b["low"]) for b in bars]
        closes = [float(b["close"]) for b in bars]
        vols = [float(b["volume"]) for b in bars]
        return dates, opens, highs, lows, closes, vols
    except (ValueError, KeyError):
        return [], [], [], [], [], []


def get_minute(code, ndays=1):
    """
    获取分时数据。
    code: 6位股票代码，如 '603687'
    返回 [(datetime, open, high, low, close, volume, amount, avg_price), ...]
    """
    d = _get(f"minute/{code}", {"ndays": ndays})
    if not d or "data" not in d:
        return []
    raw = d["data"]
    inner = raw.get("data", {})
    # 实际结构: {"rc":0, "rt":10, ..., "data":{"code":"603687","trends":[...]}}
    # inner 已经是 {"code":..., "trends": [...]}
    if isinstance(inner, dict):
        trends_list = inner.get("trends", [])
    elif isinstance(inner, list):
        trends_list = inner
    else:
        trends_list = []
    if not trends_list:
        return []
    result = []
    for line in trends_list:
        if isinstance(line, list):
            line = ",".join(str(x) for x in line)
        if not line.strip():
            continue
        parts = line.split(",")
        if len(parts) < 7:
            continue
        try:
            dt = datetime.strptime(parts[0], "%Y-%m-%d %H:%M")
            open_ = float(parts[1])
            high = float(parts[2])
            low = float(parts[3])
            close = float(parts[4])
            vol = float(parts[5])
            amount = float(parts[6])
            avg = float(parts[7]) if len(parts) > 7 else close
            result.append((dt, open_, high, low, close, vol, amount, avg))
        except (ValueError, IndexError):
            continue
    return result


def get_market_overview(date):
    """
    市场概况。
    返回 {date, ztCount, dtCount, zbgCount, marketTemp, indices: [...]}
    """
    date_str = str(date).replace("-", "")
    d = _get("market-overview", {"date": date_str})
    if not d or "data" not in d:
        return {}
    raw = d["data"]
    if isinstance(raw, list) and len(raw) > 0:
        return raw[0]
    return raw


def get_limit_up_filter(date, continue_num_min=2, limit=50):
    """
    涨停筛选。
    返回 [{code, name, level, industry, reason, ...}, ...]
    """
    date_str = str(date).replace("-", "")
    d = _get("limit-up/filter", {
        "date": date_str,
        "continueNumMin": continue_num_min,
        "limit": limit,
    })
    if not d or "data" not in d:
        return []
    raw = d["data"]
    items = raw if isinstance(raw, list) else raw.get("items", [])
    return items


